            <h1 className="cg" style={{ fontSize: 40, color: "#4a3540", lineHeight: 1, fontWeight: 400 }}>Work <span style={{ color: "#d4829a", fontStyle: "italic" }}>Hub</span> <span style={{ fontSize: 24, opacity: .35 }}>✦</span></h1>
